import { defineStore } from 'pinia'
import { fetchTasks as apiFetchTasks, createTask as apiCreateTask } from '@/api/taskApi'
import type { Task } from '@/types/task'

export const useTaskStore = defineStore('task', {
  state: () => ({
    tasks: [] as Task[],
    page: 0,
    size: 20,
    totalElements: 0,
    totalPages: 0,
    keyword: '',
    priorityFilter: null as string | null,
    statusFilter: null as string | null,
    loading: false,
    error: null as string | null,
  }),

  actions: {
    async fetchTasks() {
      this.loading = true
      this.error = null
      try {
        const response = await apiFetchTasks({
          page: this.page,
          size: this.size,
          keyword: this.keyword,
          priority: this.priorityFilter,
          status: this.statusFilter,
        })
        this.tasks = response.content
        this.totalElements = response.totalElements
        this.totalPages = response.totalPages
      } catch (e: any) {
        this.error = e.message || 'An error occurred'
      } finally {
        this.loading = false
      }
    },

    async setKeyword(keyword: string) {
      this.keyword = keyword
      this.page = 0
      await this.fetchTasks()
    },

    async setPriorityFilter(priority: string | null) {
      this.priorityFilter = priority
      this.page = 0
      await this.fetchTasks()
    },

    async setStatusFilter(status: string | null) {
      this.statusFilter = status
      this.page = 0
      await this.fetchTasks()
    },

    async setPage(page: number) {
      this.page = page
      await this.fetchTasks()
    },

    async createTask(data: Record<string, any>) {
      await apiCreateTask(data)
      await this.fetchTasks()
    },
  },
})

export enum Priority {
  HIGH = 'HIGH',
  MEDIUM = 'MEDIUM',
  LOW = 'LOW',
}

export enum TaskStatus {
  TODO = 'TODO',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE',
  CLOSED = 'CLOSED',
}

export interface Task {
  id: number
  title: string
  description: string | null
  priority: Priority | string
  status: TaskStatus | string
  createdBy: number
  createdAt: string
  updatedAt: string | null
}

export interface PageResponse<T> {
  content: T[]
  page: number
  size: number
  totalElements: number
  totalPages: number
}

export interface CreateTaskRequest {
  title: string
  description?: string
  priority?: Priority | string
}

