  const titleEl = allElements.find((el) => el.text().includes('Clickable Task'))
  if (titleEl) {
    await titleEl.trigger('click')
  }
}
await wrapper.vm.$nextTick()
expect(router.currentRoute.value.path).toBe('/tasks/42')
```

The test expects the route to change after `trigger + nextTick`. For this to work with `router.push`, the push would need to complete within those microtask boundaries. But my debugging shows it doesn't.

